import './types.js';
import { compareTexts } from './utils/text.js';
import { normalizeExtractionResult, toUint8Array } from './utils/pdf.js';

/**
 * Extract text from PDF data using provided extractor function
 * @param {ArrayBuffer|Uint8Array|Buffer} pdfData - PDF data
 * @param {Function} extractorFn - Function to extract text from PDF data
 * @returns {Promise<string>} Extracted text content
 */
export async function extractPdfText(pdfData, extractorFn) {
  if (!extractorFn) {
    throw new Error('extractorFn is required. Please provide a PDF text extraction function.');
  }

  try {
    const uint8Array = toUint8Array(pdfData);
    const result = await extractorFn(uint8Array);
    return normalizeExtractionResult(result);
  } catch (error) {
    throw new Error(`Failed to extract text from PDF: ${error.message}`);
  }
}

/**
 * Compare two PDFs using provided text content or extraction function
 * @param {ArrayBuffer|Uint8Array|Buffer|string} pdf1 - First PDF data or text content
 * @param {ArrayBuffer|Uint8Array|Buffer|string} pdf2 - Second PDF data or text content
 * @param {import('./types.js').CompareOptions & {extractorFn?: Function}} [options] - Comparison options
 * @returns {Promise<import('./types.js').DiffResult>} Comparison result
 */
export async function comparePdfs(pdf1, pdf2, options = {}) {
  const { ignoreWhitespace = false, ignoreCase = false, mode = 'char', extractorFn } = options;
  
  let text1, text2;
  
  // If inputs are strings, use them directly
  if (typeof pdf1 === 'string' && typeof pdf2 === 'string') {
    text1 = pdf1;
    text2 = pdf2;
  } else {
    // Extract text from PDF data
    if (!extractorFn) {
      throw new Error('extractorFn is required when comparing PDF data. Please provide a PDF text extraction function.');
    }
    
    text1 = await extractPdfText(/** @type {ArrayBuffer|Uint8Array|Buffer} */ (pdf1), extractorFn);
    text2 = await extractPdfText(/** @type {ArrayBuffer|Uint8Array|Buffer} */ (pdf2), extractorFn);
  }
  
  return compareTexts(text1, text2, { ignoreWhitespace, ignoreCase, mode });
}

// Re-export utilities
export { compareTexts } from './utils/text.js';
export { formatDiff } from './utils/format.js';